#!/usr/bin/env bash
# ============================================================================
# Database Safety Guard — v{{VERSION}}
# Event: PreToolUse | Matcher: Bash
# Generated by {{PROJECT_NAME}} harness-marketplace plugin
# Reads JSON from stdin (Claude Code v2 hook format)
# Exit: 0 = allow, 2 = deny (Claude sees stderr)
# ============================================================================
set -euo pipefail

# shellcheck disable=SC1091
source "$(dirname "$0")/_log.sh"
# shellcheck disable=SC1091
source "$(dirname "$0")/_parse.sh"

# ═══ GENERATED RULES (overwritten on upgrade) ═══

{{CONDITION:has_database}}

COMMAND="${TOOL_COMMAND:-}"

if [[ -z "$COMMAND" ]]; then
  exit 0
fi

# Convert command to uppercase for case-insensitive matching
COMMAND_UPPER="$(echo "$COMMAND" | tr '[:lower:]' '[:upper:]')"

# --- Dangerous SQL patterns ---

# DROP TABLE
if echo "$COMMAND_UPPER" | grep -qE 'DROP\s+TABLE'; then
  log_block "db-safety" "drop-table" "command=$COMMAND"
  echo "[DB-SAFETY] Dangerous SQL detected: DROP TABLE" >&2
  echo "Command: $COMMAND" >&2
  echo "This operation would permanently destroy a database table." >&2
  echo "If this is intentional, run the command manually outside of Claude." >&2
  exit 2
fi

# DROP DATABASE
if echo "$COMMAND_UPPER" | grep -qE 'DROP\s+DATABASE'; then
  log_block "db-safety" "drop-database" "command=$COMMAND"
  echo "[DB-SAFETY] Dangerous SQL detected: DROP DATABASE" >&2
  echo "Command: $COMMAND" >&2
  echo "This operation would permanently destroy an entire database." >&2
  exit 2
fi

# TRUNCATE
if echo "$COMMAND_UPPER" | grep -qE 'TRUNCATE\s'; then
  log_block "db-safety" "truncate" "command=$COMMAND"
  echo "[DB-SAFETY] Dangerous SQL detected: TRUNCATE" >&2
  echo "Command: $COMMAND" >&2
  echo "This operation would remove all rows from a table." >&2
  exit 2
fi

# DELETE FROM without WHERE clause
if echo "$COMMAND_UPPER" | grep -qE 'DELETE\s+FROM\s' && ! echo "$COMMAND_UPPER" | grep -qE 'DELETE\s+FROM\s+\S+\s+WHERE'; then
  log_block "db-safety" "delete-without-where" "command=$COMMAND"
  echo "[DB-SAFETY] Dangerous SQL detected: DELETE FROM without WHERE clause" >&2
  echo "Command: $COMMAND" >&2
  echo "This would delete ALL rows from a table. Add a WHERE clause." >&2
  exit 2
fi

# ALTER TABLE DROP COLUMN
if echo "$COMMAND_UPPER" | grep -qE 'ALTER\s+TABLE\s+\S+\s+DROP\s+COLUMN'; then
  log_block "db-safety" "alter-drop-column" "command=$COMMAND"
  echo "[DB-SAFETY] Potentially dangerous SQL detected: ALTER TABLE ... DROP COLUMN" >&2
  echo "Command: $COMMAND" >&2
  echo "This operation would permanently remove a column and its data." >&2
  exit 2
fi

# --- Direct DB connection strings in commands ---

# Check for connection strings that may contain credentials
if echo "$COMMAND" | grep -qE '(mysql|psql|mongo|redis-cli)\s.*(-p\s|--password|://)'; then
  log_block "db-safety" "cli-credentials" "command=$COMMAND"
  echo "[DB-SAFETY] Direct database connection with credentials detected." >&2
  echo "Avoid passing credentials directly in commands." >&2
  echo "Use environment variables or connection profiles instead." >&2
  exit 2
fi

# Check for database URLs with embedded credentials
if echo "$COMMAND" | grep -qE '(postgres|postgresql|mysql|mongodb|redis)://[^/]*:[^/]*@'; then
  log_block "db-safety" "url-credentials" "command=$COMMAND"
  echo "[DB-SAFETY] Database connection string with embedded credentials detected." >&2
  echo "Use environment variables for connection strings instead." >&2
  exit 2
fi

{{/CONDITION:has_database}}

# ═══ CUSTOM RULES BELOW (preserved on upgrade) ═══

# Add your own database safety rules here.
# They will be preserved when the plugin is upgraded.
#
# Example:
#   if echo "$COMMAND_UPPER" | grep -qE 'UPDATE\s+users\s+SET.*role.*admin'; then
#     log_block "db-safety" "custom-bulk-admin" "command=$COMMAND"
#     echo "[DB-SAFETY] Custom rule: bulk admin role assignment blocked" >&2
#     exit 2
#   fi

exit 0
